.compname { /* Sender (horizontal row left) | Absender (horizonale Zeile links) */
  display: none;
}

td.address { /* Recipient (textarea left) | Empfänger (Textbereich links) */
	color: #003956 !important;
        font-size: 0px !important;
}


td.sender { /* Sender (textarea right) | Absender (Textbereich rechts) */
  display: none;
}


/* Text elements | Textelemente */

.type1.item1 { /* Cover Sheet: 1st text area / Deckblatt: erster Textbereich */
  color: #ffffff !important;  
padding: 0px 0px 0px 0px !important;
}

