  font-family: Helvetica, Arial, sans-serif !important;
  font-size: 11px !important;
  line-height: 24px;
  color: #000000 !important;
}


.type3.copy span {
  font-size: 12px !important;
  line-height: 24px !important;
  color: #000000 !important;
}

