type7  = Subtotal / Zwischensumme
type8  = Total net / Gesamtsumme netto
type9  = Gross sum / Gesamtsumme brutto
type10 = VAT / Mehrwertsteuer
type11 = Group total net / Gruppensumme netto
type12 = Group total gross / Gruppensumme brutto
*/

