  font-size: 12px !important;
  font-weight: bold !important;
  border-style: none !important;
  border-top: solid 1px #003956 !important;
  margin: 0px !important;
  padding: 10px 0px 10px 0px !important;
}

.type7 div, .type8 div, .type9, .type9 div, .type11, .type11 div  { /* Sums / Summenelemente */
  background-color: #f5f3f2;
}

.type7 span, .type8 span, .type9 span, .type10 span, .type11 span, .type12 span, .type15 span, .type16 span { /* Sum values / Werte der Summenelemente */
  font-family: Helvetica, Arial, sans-serif !important;
  font-size: 11px !important;
  font-weight: bold;
  color: #000000 !important;
  padding: 0px 3px 0px 1px;
  
}

.type13 { /* Page break | Seitenumbruch */
}


